+    [NonDebuggable]
+    local procedure GetCustomTenantOAuthToken(var UserName: Text; var AccessToken: SecretText; SMTPAccount: Record "SMTP Account")
+    var
+        HttpClient: HttpClient;
+        HttpContent: HttpContent;
+        Headers: HttpHeaders;
+        Body: Text;
+        Resp: HttpResponseMessage;
+        RespTxt: Text;
+        JsonObj: JsonObject;
+        TokenTxt: Text;
+        Authority: Text;
+        ClientSecret: SecretText;
+        ClientID: SecretText;
+    begin
+        Authority := SMTPAccount."Authority URL";
+        if Authority = '' then
+            Error('SMTP Authority cannot be empty!');
+
+        GetValueFromStorage(SMTPAccount."Client Id", ClientID);
+        GetValueFromStorage(SMTPAccount."Client Secret Storage Id", ClientSecret);
+        Body := 'client_id=' + ClientID.Unwrap() +
+                '&client_secret=' + ClientSecret.Unwrap() +
+                '&scope=' + 'https://outlook.office365.com/.default' +
+                '&grant_type=client_credentials';
+
+        HttpContent.WriteFrom(Body);
+        HttpContent.GetHeaders(Headers);
+        Headers.Clear();
+        Headers.Add('Content-Type', 'application/x-www-form-urlencoded');
+
+        HttpClient.Post(Authority, HttpContent, Resp);
+        Resp.Content().ReadAs(RespTxt);
+
+        JsonObj.ReadFrom(RespTxt);
+        TokenTxt := JsonObj.GetText('access_token');
+
+        UserName := SMTPAccount."Email Address";
