+    local procedure GetPersonContactsFilter(): Text
+    var
+        ContactBusinessRelation: Record "Contact Business Relation";
+        Contact: Record Contact;
+        FilterText: Text;
+        ContactNo: Code[20];
+    begin
+        // Get all contacts related to this customer through business relations
+        ContactBusinessRelation.SetRange("Link to Table", ContactBusinessRelation."Link to Table"::Customer);
+        ContactBusinessRelation.SetRange("No.", "No.");
+        if ContactBusinessRelation.FindSet() then
+            repeat
+                ContactNo := ContactBusinessRelation."Contact No.";
+                if Contact.Get(ContactNo) then begin
+                    // Add the contact itself if it's a Person
+                    if Contact.Type = Contact.Type::Person then begin
+                        if FilterText <> '' then
+                            FilterText += '|';
+                        FilterText += ContactNo;
+                    end;
+                    // Add all Person contacts linked to this contact (if it's a Company)
+                    if Contact.Type = Contact.Type::Company then begin
+                        Contact.Reset();
+                        Contact.SetRange("Company No.", ContactNo);
+                        Contact.SetRange(Type, Contact.Type::Person);
+                        if Contact.FindSet() then
+                            repeat
+                                if FilterText <> '' then
+                                    FilterText += '|';
+                                FilterText += Contact."No.";
+                            until Contact.Next() = 0;
+                    end;
+                end;
+            until ContactBusinessRelation.Next() = 0;
+
+        exit(FilterText);
+    end;
