        Assert.IsTrue((StrPos(NoText[1], 'AND 76/100') = 0) and (StrPos(NoText[2], 'AND 76/100 ' + Currency.Description) > 0), StrSubstNo(AndCentsInNoText2Msg, 'AND 76/100'));
