+
+            Word := Words.Get(i).Trim();
+            if Word <> '' then
+                Initials += Word.ToUpper() [1];
+        end;
+
+        // If we have no initials or only one character, fall back to first characters
+        if StrLen(Initials) <= 1 then
+            Initials := CopyStr(AgentName.ToUpper(), 1, MaxStrLen(Initials));
+
